import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, Layers, Hash, Search } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminTaxonomy = () => {
  const [data, setData] = useState<any>({ themes: [], tags: [] });
  const [search, setSearch] = useState('');

  const fetchAll = async () => {
    try {
      const res: any = await AdminService.getAllTaxonomy();
      setData(res.data?.data || { themes: [], tags: [] });
    } catch (err) { toast.error("Sync Failed"); }
  };

  useEffect(() => { fetchAll(); }, []);

  const handleDelete = async (id: string, type: 'theme' | 'tag') => {
    if (!window.confirm(`Delete this ${type}?`)) return;
    try {
      await AdminService.deleteTaxonomy(id, type);
      toast.success("Purged");
      fetchAll();
    } catch (err) { toast.error("Delete failed"); }
  };

  const filterList = (list: any[], key: string) => 
    list.filter(item => (item[key] || "").toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase italic text-white">Archive <span className="text-primary">Taxonomy</span></h1>
          <p className="text-gray-500 font-bold uppercase text-[10px] tracking-widest mt-1">Classification Management</p>
        </div>
        <div className="flex gap-3">
          <Link to="/admin/taxonomy/add/theme" className="bg-white/5 text-white border border-white/10 px-4 py-3 rounded-xl font-black text-[9px] uppercase tracking-widest flex items-center gap-2 hover:bg-primary hover:text-black transition-all">
            <Plus size={14} /> New Theme
          </Link>
          <Link to="/admin/taxonomy/add/tag" className="bg-white/5 text-white border border-white/10 px-4 py-3 rounded-xl font-black text-[9px] uppercase tracking-widest flex items-center gap-2 hover:bg-primary hover:text-black transition-all">
            <Plus size={14} /> New Tag
          </Link>
        </div>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
        <input 
          placeholder="Search themes or tags..." 
          className="w-full bg-white/5 border border-white/10 p-4 pl-12 rounded-2xl outline-none focus:border-primary text-white text-xs font-bold"
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
        {/* Themes Column */}
        <div className="space-y-4">
          <h3 className="flex items-center gap-2 font-black uppercase text-xs italic text-gray-400"><Layers size={14}/> Themes</h3>
          <div className="grid gap-2">
            {filterList(data.themes, 'Theme_Name').map((t: any) => (
              <div key={t._id} className="bg-[#0f0f0f] p-4 rounded-2xl border border-white/5 flex justify-between items-center group">
                <div>
                  <span className="text-[8px] font-black text-primary block">{t.Theme_ID}</span>
                  <span className="text-[11px] font-bold text-white uppercase">{t.Theme_Name}</span>
                </div>
                <button onClick={() => handleDelete(t._id, 'theme')} className="text-gray-600 hover:text-red-500"><Trash2 size={14}/></button>
              </div>
            ))}
          </div>
        </div>

        {/* Tags Column */}
        <div className="space-y-4">
          <h3 className="flex items-center gap-2 font-black uppercase text-xs italic text-gray-400"><Hash size={14}/> Tags</h3>
          <div className="flex flex-wrap gap-2">
            {filterList(data.tags, 'Tag_Name').map((t: any) => (
              <div key={t._id} className="bg-white/5 border border-white/10 px-4 py-2 rounded-xl flex items-center gap-3 group">
                <span className="text-[10px] font-black text-gray-300 uppercase">#{t.Tag_Name}</span>
                <button onClick={() => handleDelete(t._id, 'tag')} className="text-gray-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"><Trash2 size={12}/></button>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};
